import{_ as t,c as s,o as i,az as e}from"./chunks/framework.OpiqYVxT.js";const c=JSON.parse('{"title":"QQ 平台对接（OneBot V11）","description":"","frontmatter":{},"headers":[],"relativePath":"guide/platforms/qq.md","filePath":"guide/platforms/qq.md","lastUpdated":1777332424000}'),n={name:"guide/platforms/qq.md"};function o(l,a,p,h,d,r){return i(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="qq-平台对接-onebot-v11" tabindex="-1">QQ 平台对接（OneBot V11） <a class="header-anchor" href="#qq-平台对接-onebot-v11" aria-label="Permalink to &quot;QQ 平台对接（OneBot V11）&quot;">​</a></h1><p>NekoBot 当前通过 OneBot V11 协议接入 QQ。推荐搭配 NapCatQQ 等 OneBot V11 实现使用。</p><h2 id="连接方式" tabindex="-1">连接方式 <a class="header-anchor" href="#连接方式" aria-label="Permalink to &quot;连接方式&quot;">​</a></h2><p>当前实现是 <strong>反向 WebSocket</strong>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NapCatQQ / OneBot 实现 -&gt; ws://NekoBot:6299/ws -&gt; NekoBot</span></span></code></pre></div><p>NekoBot 自己启动 WebSocket 服务，OneBot 实现作为客户端连接进来。</p><h2 id="nekobot-配置" tabindex="-1">NekoBot 配置 <a class="header-anchor" href="#nekobot-配置" aria-label="Permalink to &quot;NekoBot 配置&quot;">​</a></h2><p>编辑 <code>data/config.json</code> 的 <code>platforms</code> 数组：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;platforms&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;onebot_v11&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;instance_uuid&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;qq_bot_1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;enabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;host&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.0.0.0&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;port&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6299</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;path&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/ws&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;access_token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;your-token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;self_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;123456789&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;command_prefix&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>如果不需要访问令牌，可将 <code>access_token</code> 设为空字符串或删除该字段。公网或跨机器部署时建议设置访问令牌。</p><h2 id="napcatqq-配置" tabindex="-1">NapCatQQ 配置 <a class="header-anchor" href="#napcatqq-配置" aria-label="Permalink to &quot;NapCatQQ 配置&quot;">​</a></h2><p>在 NapCatQQ 中添加 WebSocket 客户端连接，目标地址指向 NekoBot：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ws://127.0.0.1:6299/ws</span></span></code></pre></div><p>如果 NekoBot 和 NapCatQQ 不在同一台机器，将 <code>127.0.0.1</code> 改为 NekoBot 所在机器的 IP 或域名。</p><p>如果 NekoBot 配置了 <code>access_token</code>，NapCatQQ 中也需要填相同 token，或通过 <code>Authorization: Bearer &lt;token&gt;</code> 方式发送。</p><h2 id="端口说明" tabindex="-1">端口说明 <a class="header-anchor" href="#端口说明" aria-label="Permalink to &quot;端口说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>服务</th><th>默认端口</th></tr></thead><tbody><tr><td>WebUI/API</td><td><code>6285</code></td></tr><tr><td>OneBot V11 WebSocket</td><td><code>6299</code></td></tr></tbody></table><p>两个端口不能相同，否则启动会失败。</p><h2 id="启动顺序" tabindex="-1">启动顺序 <a class="header-anchor" href="#启动顺序" aria-label="Permalink to &quot;启动顺序&quot;">​</a></h2><p>推荐顺序：</p><ol><li>启动 NekoBot</li><li>确认日志出现 OneBot V11 transport listening</li><li>启动 NapCatQQ 或启用其 WebSocket 客户端</li><li>在 QQ 中发送消息测试</li></ol><h2 id="支持的消息" tabindex="-1">支持的消息 <a class="header-anchor" href="#支持的消息" aria-label="Permalink to &quot;支持的消息&quot;">​</a></h2><p>当前 OneBot V11 适配器会标准化以下常见消息段：</p><table tabindex="0"><thead><tr><th>消息段</th><th>说明</th></tr></thead><tbody><tr><td><code>text</code></td><td>文本</td></tr><tr><td><code>at</code></td><td>@ 用户</td></tr><tr><td><code>reply</code></td><td>回复消息</td></tr><tr><td><code>image</code></td><td>图片</td></tr><tr><td><code>record</code></td><td>语音</td></tr><tr><td><code>video</code></td><td>视频</td></tr></tbody></table><p>框架会将消息解析为平台无关事件，插件通常只需要读取 <code>plain_text</code> 或通过上下文回复。</p><h2 id="命令触发" tabindex="-1">命令触发 <a class="header-anchor" href="#命令触发" aria-label="Permalink to &quot;命令触发&quot;">​</a></h2><p>默认命令前缀为 <code>/</code>。例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/help</span></span>
<span class="line"><span>/hello NekoBot</span></span></code></pre></div><p>可在平台配置中修改 <code>command_prefix</code>。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="napcatqq-连接不上" tabindex="-1">NapCatQQ 连接不上 <a class="header-anchor" href="#napcatqq-连接不上" aria-label="Permalink to &quot;NapCatQQ 连接不上&quot;">​</a></h3><p>检查：</p><ol><li>NekoBot 是否已启动</li><li><code>host</code> / <code>port</code> / <code>path</code> 是否和 NapCatQQ 连接地址一致</li><li>防火墙是否允许访问端口 <code>6299</code></li><li><code>access_token</code> 是否一致</li><li>WebUI 端口 <code>6285</code> 是否误填成 OneBot 端口</li></ol><h3 id="收到消息但不回复" tabindex="-1">收到消息但不回复 <a class="header-anchor" href="#收到消息但不回复" aria-label="Permalink to &quot;收到消息但不回复&quot;">​</a></h3><p>检查：</p><ol><li>是否配置了可用的 LLM Provider</li><li>插件是否启用</li><li>群聊是否需要 @ 或唤醒词</li><li>日志中是否有 Provider、权限或插件错误</li></ol><h3 id="如何调用-onebot-api" tabindex="-1">如何调用 OneBot API <a class="header-anchor" href="#如何调用-onebot-api" aria-label="Permalink to &quot;如何调用 OneBot API&quot;">​</a></h3><p>插件一般通过 <code>reply()</code> 回复消息。高级场景可以在平台适配器或扩展代码中调用 <code>call_api()</code>，action 名称遵循 OneBot V11 规范，例如 <code>send_group_msg</code>、<code>get_msg</code>、<code>set_group_ban</code>。</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="https://11.onebot.dev/" target="_blank" rel="noreferrer">OneBot V11 规范</a></li><li><a href="https://github.com/NapNeko/NapCatQQ" target="_blank" rel="noreferrer">NapCatQQ GitHub</a></li><li><a href="./../platform-configuration.html">平台配置</a></li></ul>`,40)])])}const E=t(n,[["render",o]]);export{c as __pageData,E as default};
